import{a as t}from"./index-qFyJwsfU.js";const o=t.create({baseURL:"/api",timeout:1e4,headers:{"Content-Type":"application/json"}});o.interceptors.request.use(e=>{const r=localStorage.getItem("token");return r&&(e.headers.Authorization=`Bearer ${r}`),e},e=>Promise.reject(e));o.interceptors.response.use(e=>e.data,e=>{if(e.response)switch(e.response.status){case 401:localStorage.removeItem("token"),localStorage.removeItem("user"),window.location.href="/login";break;case 403:console.error("禁止访问");break;case 404:console.error("资源不存在");break;case 500:console.error("服务器错误");break;default:console.error("请求失败")}else e.request?console.error("网络错误"):console.error("请求配置出错");return Promise.reject(e)});
